SELECT waterbody_id, capacity, comments
FROM parking
WHERE capacity IS NOT NULL;

SELECT name, town
FROM waterbodies
ORDER BY town ASC;

SELECT name 
FROM waterbodies 
WHERE agency_id = (SELECT agency_id FROM agencies WHERE agency_name = 'OPRHP');

SELECT waterbodies.name 
FROM waterbodies 
JOIN restrictions ON waterbodies.waterbody_id = restrictions.waterbody_id;

SELECT waterbodies.name, towns.town_name
FROM waterbodies
JOIN towns ON waterbodies.town = towns.town_id;
